73	func (r *ResourceRepository) Update(ctx context.Context, res *models.Resource) error {
74		query := `UPDATE resources SET title = $1, description = $2, visibility = $3, node_id = $4, link_url = $5, updated_at = NOW()
75			WHERE id = $6`
76		result, err := r.db.ExecContext(ctx, query, res.Title, res.Description, res.Visibility, res.NodeID, res.LinkURL, res.ID)
77		if err != nil {
78			return fmt.Errorf("resource_repo.Update: %w", err)
79		}
80		rows, _ := result.RowsAffected()
81		if rows == 0 {
82			return fmt.Errorf("resource_repo.Update: resource not found")
83		}
84		return nil
85	}
86	
87	func (r *ResourceRepository) UpdateVisibility(ctx context.Context, id uuid.UUID, visibility models.ResourceVisibility) error {
88		query := `UPDATE resources SET visibility = $1, updated_at = NOW() WHERE id = $2`
89		_, err := r.db.ExecContext(ctx, query, visibility, id)
90		if err != nil {
91			return fmt.Errorf("resource_repo.UpdateVisibility: %w", err)
92		}
93		return nil
94	}
95	
96	func (r *ResourceRepository) UpdateLatestVersion(ctx context.Context, resourceID, versionID uuid.UUID) error {
97		query := `UPDATE resources SET latest_version_id = $1, updated_at = NOW() WHERE id = $2`
98		_, err := r.db.ExecContext(ctx, query, versionID, resourceID)
99		if err != nil {
100			return fmt.Errorf("resource_repo.UpdateLatestVersion: %w", err)
101		}
102		return nil
103	}
104	
105	func (r *ResourceRepository) Search(ctx context.Context, courseID uuid.UUID, query string, offset, limit int) ([]models.Resource, error) {
106		var resources []models.Resource
107		searchQuery := `SELECT DISTINCT r.id, r.course_id, r.node_id, r.title, r.description, r.resource_type, r.visibility, r.link_url, r.latest_version_id, r.created_by, r.created_at, r.updated_at
108			FROM resources r
109			LEFT JOIN resource_versions rv ON rv.resource_id = r.id
110			WHERE r.course_id = $1
111			AND (
112				r.search_vector @@ plainto_tsquery('english', $2)
113				OR rv.text_search_vector @@ plainto_tsquery('english', $2)
114			)
115			ORDER BY r.created_at DESC
116			LIMIT $3 OFFSET $4`
117		if err := r.db.SelectContext(ctx, &resources, searchQuery, courseID, query, limit, offset); err != nil {
118			return nil, fmt.Errorf("resource_repo.Search: %w", err)
119		}
120		return resources, nil
121	}
122	
123	func (r *ResourceRepository) SearchWithVisibility(ctx context.Context, courseID uuid.UUID, query string, visibility models.ResourceVisibility, offset, limit int) ([]models.Resource, error) {
124		var resources []models.Resource
125		searchQuery := `SELECT DISTINCT r.id, r.course_id, r.node_id, r.title, r.description, r.resource_type, r.visibility, r.link_url, r.latest_version_id, r.created_by, r.created_at, r.updated_at
126			FROM resources r
127			LEFT JOIN resource_versions rv ON rv.resource_id = r.id
128			WHERE r.course_id = $1
129			AND r.visibility = $5
130			AND (
131				r.search_vector @@ plainto_tsquery('english', $2)
132				OR rv.text_search_vector @@ plainto_tsquery('english', $2)
133			)
134			ORDER BY r.created_at DESC
135			LIMIT $3 OFFSET $4`
136		if err := r.db.SelectContext(ctx, &resources, searchQuery, courseID, query, limit, offset, visibility); err != nil {
137			return nil, fmt.Errorf("resource_repo.SearchWithVisibility: %w", err)
138		}
139		return resources, nil
140	}
