142	func (r *ResourceRepository) Delete(ctx context.Context, id uuid.UUID) error {
143		query := `DELETE FROM resources WHERE id = $1`
144		_, err := r.db.ExecContext(ctx, query, id)
145		if err != nil {
146			return fmt.Errorf("resource_repo.Delete: %w", err)
147		}
148		return nil
149	}
