183	func (s *ResourceService) UpdateResource(ctx context.Context, id uuid.UUID, req *dto.UpdateResourceRequest, actorID uuid.UUID, callerRole models.Role) (*models.Resource, []string, error) {
184		resource, err := s.resourceRepo.GetByID(ctx, id)
185		if err != nil {
186			return nil, nil, ErrResourceNotFound
187		}
188	
189		// Require course staff or admin
190		if err := s.requireCourseStaff(ctx, resource.CourseID, actorID, callerRole); err != nil {
191			return nil, nil, err
192		}
193	
194		if req.Title != nil {
195			resource.Title = *req.Title
196		}
197		if req.Description != nil {
198			resource.Description = req.Description
199		}
200		if req.Visibility != nil {
201			vis := models.ResourceVisibility(*req.Visibility)
202			if !models.ValidVisibilities[vis] {
203				return nil, nil, fmt.Errorf("invalid visibility: %s", *req.Visibility)
204			}
205			resource.Visibility = vis
206		}
207		if req.NodeID != nil {
208			if *req.NodeID == "" {
209				resource.NodeID = nil
210			} else {
211				nid, err := uuid.Parse(*req.NodeID)
212				if err != nil {
213					return nil, nil, fmt.Errorf("invalid node_id")
214				}
215				resource.NodeID = &nid
216			}
217		}
218		if req.LinkURL != nil {
219			resource.LinkURL = req.LinkURL
220		}
221	
222		if err := s.resourceRepo.Update(ctx, resource); err != nil {
223			return nil, nil, err
224		}
225	
226		// Update tags if provided
227		var tags []string
228		if req.Tags != nil {
229			if err := validateTags(req.Tags); err != nil {
230				return nil, nil, err
231			}
232			tags = s.replaceTags(ctx, resource.ID, req.Tags)
233		} else {
234			tags, _ = s.getTagStrings(ctx, id)
235		}
236	
237		s.audit.Log(ctx, "resource", resource.ID, actorID, "updated", map[string]interface{}{
238			"title":      resource.Title,
239			"visibility": string(resource.Visibility),
240		})
241	
242		return resource, tags, nil
243	}
