245	func (s *ResourceService) SearchResources(ctx context.Context, courseID uuid.UUID, query string, callerID uuid.UUID, callerRole models.Role, offset, limit int) ([]models.Resource, error) {
246		if limit <= 0 {
247			limit = 20
248		}
249		if limit > 100 {
250			limit = 100
251		}
252		if query == "" {
253			return nil, fmt.Errorf("search query is required")
254		}
255	
256		// Admin and course staff: search all visibility levels
257		if callerRole == models.RoleAdministrator {
258			return s.resourceRepo.Search(ctx, courseID, query, offset, limit)
259		}
260	
261		m, err := s.memberRepo.GetByAccountAndCourse(ctx, callerID, courseID)
262		if err != nil {
263			return nil, ErrNotCourseMember
264		}
265	
266		if m.Role == models.MembershipRoleStaff {
267			return s.resourceRepo.Search(ctx, courseID, query, offset, limit)
268		}
269	
270		// Enrolled users: search only Enrolled-visibility resources
271		return s.resourceRepo.SearchWithVisibility(ctx, courseID, query, models.VisibilityEnrolled, offset, limit)
272	}
