407	// Access control
408	
409	func (s *ResourceService) checkResourceAccess(ctx context.Context, resource *models.Resource, callerID uuid.UUID, callerRole models.Role) error {
410		if callerRole == models.RoleAdministrator {
411			return nil
412		}
413	
414		m, err := s.memberRepo.GetByAccountAndCourse(ctx, callerID, resource.CourseID)
415		if err != nil {
416			if errors.Is(err, sql.ErrNoRows) {
417				return ErrResourceAccessDenied
418			}
419			return err
420		}
421	
422		// Staff can see everything
423		if m.Role == models.MembershipRoleStaff {
424			return nil
425		}
426	
427		// Enrolled users can only see Enrolled-visibility resources
428		if resource.Visibility == models.VisibilityStaff {
429			return ErrResourceAccessDenied
430		}
431	
432		return nil
433	}
434	
435	// Course-level authorization helpers
436	
437	func (s *ResourceService) requireCourseStaff(ctx context.Context, courseID, actorID uuid.UUID, callerRole models.Role) error {
438		if callerRole == models.RoleAdministrator {
439			return nil
440		}
