217	func (h *ResourceHandler) DownloadVersion(c echo.Context) error {
218		versionID, err := uuid.Parse(c.Param("version_id"))
219		if err != nil {
220			return echo.NewHTTPError(http.StatusBadRequest, "invalid version id")
221		}
222	
223		callerID, _ := c.Get("account_id").(uuid.UUID)
224		callerRole, _ := c.Get("role").(models.Role)
225	
226		version, err := h.resourceService.GetDownloadPath(c.Request().Context(), versionID, callerID, callerRole)
227		if err != nil {
228			if errors.Is(err, service.ErrVersionNotFound) || errors.Is(err, service.ErrResourceNotFound) {
229				return echo.NewHTTPError(http.StatusNotFound, err.Error())
230			}
231			if errors.Is(err, service.ErrResourceAccessDenied) {
232				return echo.NewHTTPError(http.StatusForbidden, err.Error())
233			}
234			return echo.NewHTTPError(http.StatusInternalServerError, "internal server error")
235		}
236	
237		// Verify file integrity before serving
238		f, err := os.Open(version.StoragePath)
239		if err != nil {
240			return echo.NewHTTPError(http.StatusInternalServerError, "file not found on disk")
241		}
242		defer f.Close()
243	
244		hasher := sha256.New()
245		if _, err := io.Copy(hasher, f); err != nil {
246			return echo.NewHTTPError(http.StatusInternalServerError, "failed to verify file integrity")
247		}
248		actualHash := hex.EncodeToString(hasher.Sum(nil))
249		if actualHash != version.SHA256Hash {
250			return echo.NewHTTPError(http.StatusInternalServerError, "file integrity check failed")
251		}
252	
253		// Seek back to start for serving
254		f.Seek(0, io.SeekStart)
255	
256		c.Response().Header().Set("Content-Type", version.MimeType)
257		c.Response().Header().Set("Content-Disposition", fmt.Sprintf(`attachment; filename="%s"`, version.FileName))
258		c.Response().Header().Set("X-Content-SHA256", version.SHA256Hash)
259		return c.Stream(http.StatusOK, version.MimeType, f)
260	}
