17		"github.com/shopspring/decimal"
18	)
19	
20	const idempotencyWindow = 24 * time.Hour
21	
22	var (
23		ErrPaymentNotFound    = errors.New("payment not found")
24		ErrDuplicatePayment   = errors.New("duplicate idempotency key")
25		ErrNotObligation      = errors.New("payment is not in Obligation status")
26		ErrNotFailed          = errors.New("payment is not in Failed status")
27		ErrMaxRetriesExceeded = errors.New("maximum retry attempts exceeded")
28		ErrInvalidAmount      = errors.New("amount must be positive")
29		ErrReconNotFound      = errors.New("reconciliation report not found")
30	)
31	
32	type PaymentService struct {
33		repo  *repository.PaymentRepository
34		audit *AuditService
35		cfg   *config.Config
36	}
37	
38	func NewPaymentService(
39		repo *repository.PaymentRepository,
40		audit *AuditService,
41		cfg *config.Config,
42	) *PaymentService {
43		return &PaymentService{
44			repo:  repo,
45			audit: audit,
46			cfg:   cfg,
47		}
48	}
49	
50	// CreatePayment creates a new obligation with idempotency. If a duplicate key is found
51	// within 24 hours for the same account, the original entry is returned.
52	func (s *PaymentService) CreatePayment(ctx context.Context, req *dto.CreatePaymentRequest, actorID uuid.UUID) (*models.PaymentLedgerEntry, bool, error) {
53		if req.IdempotencyKey == "" {
54			return nil, false, fmt.Errorf("idempotency_key is required")
55		}
56	
57		accountID, err := uuid.Parse(req.AccountID)
58		if err != nil {
59			return nil, false, fmt.Errorf("invalid account_id")
60		}
61	
62		amount, err := decimal.NewFromString(req.AmountUSD)
63		if err != nil {
64			return nil, false, fmt.Errorf("invalid amount_usd")
65		}
66		if amount.LessThanOrEqual(decimal.Zero) {
67			return nil, false, ErrInvalidAmount
68		}
69	
70		channel := models.PaymentChannel(req.Channel)
71		if !models.ValidPaymentChannels[channel] {
72			return nil, false, fmt.Errorf("invalid channel: %s", req.Channel)
73		}
74	
75		// Check idempotency: look for active key in dedicated table within 24h window
76		now := time.Now()
77		activeKey, findErr := s.repo.FindActiveIdempotencyKey(ctx, accountID, req.IdempotencyKey, now)
78		if findErr == nil && activeKey != nil {
79			// Active key found — return original payment
80			orig, getErr := s.repo.GetByID(ctx, activeKey.PaymentID)
81			if getErr == nil {
82				return orig, true, nil
83			}
84		}
85	
86		// Clean up expired idempotency keys (best-effort)
87		s.repo.DeleteExpiredIdempotencyKeys(ctx, now)
88	
89		var refType *string
90		var refID *uuid.UUID
91		if req.ReferenceType != nil {
92			refType = req.ReferenceType
93		}
94		if req.ReferenceID != nil {
95			rid, err := uuid.Parse(*req.ReferenceID)
96			if err != nil {
97				return nil, false, fmt.Errorf("invalid reference_id")
98			}
99			refID = &rid
100		}
101	
102		idempotencyExpiry := now.Add(idempotencyWindow)
103		entry := &models.PaymentLedgerEntry{
104			ID:                   uuid.New(),
105			AccountID:            accountID,
106			IdempotencyKey:       req.IdempotencyKey,
107			AmountUSD:            amount,
108			Description:          req.Description,
109			Channel:              channel,
110			Status:               models.PaymentObligation,
111			RetryCount:           0,
112			ReferenceType:        refType,
113			ReferenceID:          refID,
114			CreatedAt:            now,
115			UpdatedAt:            now,
116			IdempotencyExpiresAt: &idempotencyExpiry,
117		}
118	
119		if err := s.repo.Create(ctx, entry); err != nil {
120			return nil, false, err
121		}
122	
123		// Record idempotency key in dedicated table
124		ik := &models.IdempotencyKey{
125			ID:             uuid.New(),
126			AccountID:      accountID,
127			IdempotencyKey: req.IdempotencyKey,
128			PaymentID:      entry.ID,
129			WindowStart:    now,
130			WindowEnd:      idempotencyExpiry,
131			CreatedAt:      now,
132		}
133		s.repo.CreateIdempotencyKey(ctx, ik)
134	
135		s.audit.Log(ctx, "payment", entry.ID, actorID, "obligation_created", map[string]interface{}{
136			"account_id":      accountID,
137			"amount_usd":      amount.String(),
138			"channel":         string(channel),
139			"idempotency_key": req.IdempotencyKey,
140		})
141	
142		return entry, false, nil
143	}
144	
145	// SignPosting is the Finance Clerk's explicit confirmation that settles an obligation.
146	func (s *PaymentService) SignPosting(ctx context.Context, paymentID, clerkID uuid.UUID) (*models.PaymentLedgerEntry, error) {
147		entry, err := s.repo.GetByID(ctx, paymentID)
148		if err != nil {
149			return nil, ErrPaymentNotFound
150		}
151	
152		if entry.Status != models.PaymentObligation {
153			return nil, ErrNotObligation
154		}
155	
156		beforeStatus := string(entry.Status)
157	
158		now := time.Now()
159		entry.Status = models.PaymentSettled
160		entry.FinanceClerkID = &clerkID
161		entry.SettledAt = &now
162	
163		if err := s.repo.Update(ctx, entry); err != nil {
164			return nil, err
165		}
166	
167		s.audit.LogExtended(ctx, &AuditEntry{
168			EntityType: "payment",
169			EntityID:   paymentID,
170			ActorID:    clerkID,
171			Action:     "posting_signed",
172			Tier:       models.TierAudit,
173			BeforeSnapshot: map[string]interface{}{
174				"status": beforeStatus,
175			},
176			AfterSnapshot: map[string]interface{}{
177				"status":           string(entry.Status),
178				"finance_clerk_id": clerkID,
179				"settled_at":       now,
180			},
181			Details: map[string]interface{}{
182				"account_id": entry.AccountID,
183				"amount_usd": entry.AmountUSD.String(),
184				"channel":    string(entry.Channel),
185			},
186		})
187	
188		return entry, nil
189	}
190	
191	// FailSettlement marks an obligation as failed (e.g., check bounced, wire rejected).
192	func (s *PaymentService) FailSettlement(ctx context.Context, paymentID, actorID uuid.UUID) (*models.PaymentLedgerEntry, error) {
193		entry, err := s.repo.GetByID(ctx, paymentID)
194		if err != nil {
195			return nil, ErrPaymentNotFound
196		}
197	
198		if entry.Status != models.PaymentObligation {
199			return nil, ErrNotObligation
200		}
201	
202		entry.Status = models.PaymentFailed
203	
204		if err := s.repo.Update(ctx, entry); err != nil {
205			return nil, err
206		}
207	
208		s.audit.Log(ctx, "payment", paymentID, actorID, "settlement_failed", map[string]interface{}{
209			"account_id": entry.AccountID,
210			"amount_usd": entry.AmountUSD.String(),
211		})
212	
213		return entry, nil
214	}
215	
216	// RetrySettlement retries a failed settlement (up to MaxSettlementRetries).
217	// On retry, it moves back to Obligation for the clerk to re-sign.
218	func (s *PaymentService) RetrySettlement(ctx context.Context, paymentID, actorID uuid.UUID) (*models.PaymentLedgerEntry, error) {
219		entry, err := s.repo.GetByID(ctx, paymentID)
220		if err != nil {
221			return nil, ErrPaymentNotFound
222		}
223	
224		if entry.Status != models.PaymentFailed {
225			return nil, ErrNotFailed
226		}
227	
228		if entry.RetryCount >= models.MaxSettlementRetries {
229			return nil, ErrMaxRetriesExceeded
230		}
231	
