76	func (s *AccountService) GetAccount(ctx context.Context, id uuid.UUID) (*models.Account, error) {
77		return s.accountRepo.GetByID(ctx, id)
78	}
79	
80	func (s *AccountService) ListAccounts(ctx context.Context, offset, limit int) ([]models.Account, error) {
81		if limit <= 0 {
82			limit = 20
83		}
84		if limit > 100 {
85			limit = 100
86		}
87		return s.accountRepo.List(ctx, offset, limit)
88	}
89	
90	func (s *AccountService) UpdateStatus(ctx context.Context, id uuid.UUID, newStatus models.Status) error {
91		if !models.ValidStatuses[newStatus] {
92			return fmt.Errorf("invalid status: %s", newStatus)
93		}
94	
95		if err := s.accountRepo.UpdateStatus(ctx, id, newStatus); err != nil {
96			return err
97		}
98	
99		// When deactivating, revoke all sessions
100		if newStatus == models.StatusDeactivated || newStatus == models.StatusFrozen {
101			if err := s.refreshTokenRepo.RevokeAllForAccount(ctx, id); err != nil {
102				return fmt.Errorf("account_service.UpdateStatus: %w", err)
103			}
104		}
105		return nil
106	}
107	
108	func (s *AccountService) ChangePassword(ctx context.Context, accountID uuid.UUID, oldPassword, newPassword string) error {
109		account, err := s.accountRepo.GetByID(ctx, accountID)
110		if err != nil {
111			return fmt.Errorf("account_service.ChangePassword: %w", err)
112		}
113	
114		if err := bcrypt.CompareHashAndPassword([]byte(account.PasswordHash), []byte(oldPassword)); err != nil {
115			return ErrInvalidCredentials
116		}
117	
118		if err := ValidatePassword(newPassword); err != nil {
119			return err
120		}
121	
122		hash, err := bcrypt.GenerateFromPassword([]byte(newPassword), s.cfg.BcryptCost)
123		if err != nil {
124			return fmt.Errorf("account_service.ChangePassword: %w", err)
125		}
126	
127		if err := s.accountRepo.UpdatePassword(ctx, accountID, string(hash)); err != nil {
128			return err
129		}
130	
131		// Revoke all refresh tokens to force re-login on all devices
132		return s.refreshTokenRepo.RevokeAllForAccount(ctx, accountID)
133	}
