23	func (h *AccountHandler) Create(c echo.Context) error {
24		var req dto.CreateAccountRequest
25		if err := c.Bind(&req); err != nil {
26			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
27		}
28		if req.Username == "" || req.Password == "" || req.Role == "" {
29			return echo.NewHTTPError(http.StatusBadRequest, "username, password, and role are required")
30		}
31	
32		account, err := h.accountService.CreateAccount(c.Request().Context(), &req)
33		if err != nil {
34			if errors.Is(err, service.ErrPasswordPolicy) {
35				return echo.NewHTTPError(http.StatusBadRequest, err.Error())
36			}
37			if errors.Is(err, service.ErrInvalidRole) {
38				return echo.NewHTTPError(http.StatusBadRequest, err.Error())
39			}
40			if errors.Is(err, service.ErrDuplicateUsername) {
41				return echo.NewHTTPError(http.StatusConflict, err.Error())
42			}
43			return echo.NewHTTPError(http.StatusInternalServerError, err.Error())
44		}
45	
46		return c.JSON(http.StatusCreated, dto.ToAccountResponse(account))
47	}
