61	func (h *AccountHandler) Get(c echo.Context) error {
62		id, err := uuid.Parse(c.Param("id"))
63		if err != nil {
64			return echo.NewHTTPError(http.StatusBadRequest, "invalid account id")
65		}
66	
67		// Allow self-access: any authenticated user can view their own account
68		callerID, _ := c.Get("account_id").(uuid.UUID)
69		callerRole, _ := c.Get("role").(models.Role)
70		if callerID != id && callerRole != models.RoleAdministrator {
71			return echo.NewHTTPError(http.StatusForbidden, "insufficient permissions")
72		}
73	
74		account, err := h.accountService.GetAccount(c.Request().Context(), id)
75		if err != nil {
76			return echo.NewHTTPError(http.StatusNotFound, "account not found")
77		}
78	
79		return c.JSON(http.StatusOK, dto.ToAccountResponse(account))
