103	func (h *AccountHandler) ChangePassword(c echo.Context) error {
104		id, err := uuid.Parse(c.Param("id"))
105		if err != nil {
106			return echo.NewHTTPError(http.StatusBadRequest, "invalid account id")
107		}
108	
109		// Only the account owner can change their own password
110		callerID, _ := c.Get("account_id").(uuid.UUID)
111		if callerID != id {
112			return echo.NewHTTPError(http.StatusForbidden, "you can only change your own password")
113		}
114	
115		var req dto.ChangePasswordRequest
116		if err := c.Bind(&req); err != nil {
117			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
118		}
119		if req.OldPassword == "" || req.NewPassword == "" {
120			return echo.NewHTTPError(http.StatusBadRequest, "old_password and new_password are required")
121		}
122	
123		if err := h.accountService.ChangePassword(c.Request().Context(), id, req.OldPassword, req.NewPassword); err != nil {
124			if errors.Is(err, service.ErrInvalidCredentials) {
125				return echo.NewHTTPError(http.StatusUnauthorized, "incorrect current password")
126			}
127			if errors.Is(err, service.ErrPasswordPolicy) {
128				return echo.NewHTTPError(http.StatusBadRequest, err.Error())
129			}
130			return echo.NewHTTPError(http.StatusInternalServerError, "internal server error")
131		}
132	
133		return c.JSON(http.StatusOK, map[string]string{"message": "password changed successfully"})
134	}
