60	}
61	
62	func (s *AuthService) Login(ctx context.Context, req *dto.LoginRequest, ipAddress string) (*dto.LoginResponse, error) {
63		account, err := s.accountRepo.GetByUsername(ctx, req.Username)
64		if err != nil {
65			// Prevent timing-based user enumeration: always hash
66			bcrypt.CompareHashAndPassword([]byte("$2a$12$000000000000000000000000000000000000000000000000000000"), []byte(req.Password))
67			return nil, ErrInvalidCredentials
68		}
69	
70		if account.Status != models.StatusActive {
71			return nil, ErrAccountNotActive
72		}
73	
74		// Check lockout
75		failCount, err := s.loginAttemptRepo.CountRecentFailures(ctx, account.ID, s.cfg.LockoutDuration)
76		if err != nil {
77			return nil, fmt.Errorf("auth_service.Login: %w", err)
78		}
79		if failCount >= s.cfg.MaxLoginAttempts {
80			return nil, ErrAccountLocked
81		}
82	
83		// Verify password
84		if err := bcrypt.CompareHashAndPassword([]byte(account.PasswordHash), []byte(req.Password)); err != nil {
85			s.recordAttempt(ctx, account.ID, false, ipAddress)
86			if s.audit != nil {
87				s.audit.LogExtended(ctx, &AuditEntry{
88					EntityType: "auth",
89					EntityID:   account.ID,
90					ActorID:    account.ID,
91					Action:     "login_failure",
92					Tier:       models.TierAccess,
93					Source:     strPtr("auth/login"),
94					Reason:     strPtr("invalid password"),
95					Details:    map[string]interface{}{"username": account.Username, "ip_address": ipAddress},
96				})
97			}
98			return nil, ErrInvalidCredentials
99		}
100	
101		// Record successful attempt
102		s.recordAttempt(ctx, account.ID, true, ipAddress)
103	
104		// Handle device fingerprint
105		var deviceID *uuid.UUID
106		if req.DeviceFingerprint != nil {
107			fpHash := s.deviceService.ComputeFingerprint(req.DeviceFingerprint.UserAgent, req.DeviceFingerprint.Attributes)
108			device, err := s.deviceService.RegisterOrUpdateDevice(ctx, account.ID, fpHash, nil)
109			if err == nil {
110				deviceID = &device.ID
111			}
112		}
113	
114		// Generate tokens
115		accessToken, err := s.tokenService.GenerateAccessToken(account)
116		if err != nil {
117			return nil, fmt.Errorf("auth_service.Login: %w", err)
118		}
119	
120		rawRefresh, hashedRefresh, err := s.tokenService.GenerateRefreshToken()
121		if err != nil {
122			return nil, fmt.Errorf("auth_service.Login: %w", err)
123		}
124	
125		now := time.Now()
126		refreshToken := &models.RefreshToken{
127			ID:        uuid.New(),
128			AccountID: account.ID,
129			TokenHash: hashedRefresh,
130			DeviceID:  deviceID,
131			ExpiresAt: now.Add(s.cfg.RefreshTokenTTL),
132			Revoked:   false,
133			CreatedAt: now,
134		}
135		if err := s.refreshTokenRepo.Create(ctx, refreshToken); err != nil {
136			return nil, fmt.Errorf("auth_service.Login: %w", err)
137		}
138	
139		// Audit: access-tier log for successful login
140		if s.audit != nil {
141			s.audit.LogExtended(ctx, &AuditEntry{
142				EntityType: "auth",
143				EntityID:   account.ID,
144				ActorID:    account.ID,
145				Action:     "login_success",
146				Tier:       models.TierAccess,
147				Source:     strPtr("auth/login"),
148				Details: map[string]interface{}{
149					"username":   account.Username,
150					"ip_address": ipAddress,
151				},
152			})
153		}
154	
155		return &dto.LoginResponse{
156			AccessToken:  accessToken,
157			RefreshToken: rawRefresh,
158			ExpiresIn:    int(s.cfg.AccessTokenTTL.Seconds()),
159			Account:      dto.ToAccountResponse(account),
160		}, nil
161	}
162	
163	func (s *AuthService) Refresh(ctx context.Context, rawRefreshToken string) (*dto.RefreshResponse, error) {
164		hashed := HashRefreshToken(rawRefreshToken)
165		stored, err := s.refreshTokenRepo.GetByHash(ctx, hashed)
166		if err != nil {
167			return nil, ErrTokenInvalid
168		}
169	
170		// Reuse detection: if token was already revoked, revoke all tokens for the account
171		if stored.Revoked {
172			s.refreshTokenRepo.RevokeAllForAccount(ctx, stored.AccountID)
173			return nil, ErrTokenReuse
174		}
175	
176		if time.Now().After(stored.ExpiresAt) {
177			return nil, ErrTokenInvalid
178		}
179	
180		// Revoke the current token
181		if err := s.refreshTokenRepo.Revoke(ctx, stored.ID); err != nil {
182			return nil, fmt.Errorf("auth_service.Refresh: %w", err)
183		}
184	
185		// Get account for new access token
186		account, err := s.accountRepo.GetByID(ctx, stored.AccountID)
187		if err != nil {
188			return nil, fmt.Errorf("auth_service.Refresh: %w", err)
189		}
190	
191		if account.Status != models.StatusActive {
192			return nil, ErrAccountNotActive
193		}
194	
195		// Generate new token pair
196		accessToken, err := s.tokenService.GenerateAccessToken(account)
197		if err != nil {
198			return nil, fmt.Errorf("auth_service.Refresh: %w", err)
199		}
200	
201		newRaw, newHashed, err := s.tokenService.GenerateRefreshToken()
202		if err != nil {
203			return nil, fmt.Errorf("auth_service.Refresh: %w", err)
204		}
205	
206		now := time.Now()
207		newRefreshToken := &models.RefreshToken{
208			ID:        uuid.New(),
209			AccountID: stored.AccountID,
210			TokenHash: newHashed,
211			DeviceID:  stored.DeviceID,
212			ExpiresAt: now.Add(s.cfg.RefreshTokenTTL),
213			Revoked:   false,
214			CreatedAt: now,
215		}
216		if err := s.refreshTokenRepo.Create(ctx, newRefreshToken); err != nil {
217			return nil, fmt.Errorf("auth_service.Refresh: %w", err)
218		}
219	
220		if s.audit != nil {
221			s.audit.LogExtended(ctx, &AuditEntry{
222				EntityType: "auth",
223				EntityID:   stored.AccountID,
224				ActorID:    stored.AccountID,
225				Action:     "token_refresh",
226				Tier:       models.TierAccess,
227				Source:     strPtr("auth/refresh"),
228			})
229		}
230	
231		return &dto.RefreshResponse{
232			AccessToken:  accessToken,
233			RefreshToken: newRaw,
234			ExpiresIn:    int(s.cfg.AccessTokenTTL.Seconds()),
235		}, nil
236	}
237	
238	func (s *AuthService) Logout(ctx context.Context, rawRefreshToken string) error {
239		hashed := HashRefreshToken(rawRefreshToken)
240		stored, err := s.refreshTokenRepo.GetByHash(ctx, hashed)
241		if err != nil {
242			if errors.Is(err, sql.ErrNoRows) {
243				return nil
244			}
245			return fmt.Errorf("auth_service.Logout: %w", err)
246		}
247		if s.audit != nil {
248			s.audit.LogExtended(ctx, &AuditEntry{
249				EntityType: "auth",
250				EntityID:   stored.AccountID,
251				ActorID:    stored.AccountID,
252				Action:     "logout",
253				Tier:       models.TierAccess,
254				Source:     strPtr("auth/logout"),
255			})
256		}
257		return s.refreshTokenRepo.Revoke(ctx, stored.ID)
258	}
259	
260	func ValidatePassword(password string) error {
261		var errs []string
262	
263		if len(password) < 12 {
264			errs = append(errs, "at least 12 characters")
265		}
266	
267		var hasUpper, hasLower, hasDigit bool
268		for _, ch := range password {
269			switch {
270			case unicode.IsUpper(ch):
271				hasUpper = true
272			case unicode.IsLower(ch):
273				hasLower = true
274			case unicode.IsDigit(ch):
275				hasDigit = true
276			}
277		}
278	
279		if !hasUpper {
280			errs = append(errs, "at least 1 uppercase letter")
281		}
282		if !hasLower {
283			errs = append(errs, "at least 1 lowercase letter")
284		}
285		if !hasDigit {
286			errs = append(errs, "at least 1 number")
287		}
288	
289		if len(errs) > 0 {
290			return fmt.Errorf("%w: password must contain %s", ErrPasswordPolicy, strings.Join(errs, ", "))
291		}
292		return nil
293	}
294	
295	func strPtr(s string) *string { return &s }
296	
297	func (s *AuthService) recordAttempt(ctx context.Context, accountID uuid.UUID, success bool, ipAddress string) {
298		attempt := &models.LoginAttempt{
299			ID:          uuid.New(),
300			AccountID:   accountID,
301			Success:     success,
302			IPAddress:   &ipAddress,
303			AttemptedAt: time.Now(),
304		}
305		s.loginAttemptRepo.Record(ctx, attempt)
306	}
