169	// Hash chain operations
170	
171	// BuildDailyHashChain computes the hash for a specific day and chains it to the previous day
172	func (s *AuditService) BuildDailyHashChain(ctx context.Context, date time.Time) (*models.AuditHashChain, error) {
173		// Check if chain already exists for this date
174		existing, err := s.repo.GetHashChainByDate(ctx, date)
175		if err == nil && existing != nil {
176			return existing, nil
177		}
178	
179		// Get all entries for the day
180		entries, err := s.repo.GetDayEntries(ctx, date)
181		if err != nil {
182			return nil, fmt.Errorf("getting day entries: %w", err)
183		}
184	
185		// Compute batch hash over all entries
186		batchHash := s.computeBatchHash(entries)
187	
188		// Get previous day's hash
189		var previousHash *string
190		prev, err := s.repo.GetLatestHashChain(ctx)
191		if err == nil && prev != nil {
192			previousHash = &prev.BatchHash
193		}
194	
195		// Chain: hash(previousHash + batchHash)
196		chainedInput := ""
197		if previousHash != nil {
198			chainedInput = *previousHash + "|"
199		}
200		chainedInput += batchHash
201		ch := sha256.Sum256([]byte(chainedInput))
202		finalHash := hex.EncodeToString(ch[:])
203	
204		chain := &models.AuditHashChain{
205			ID:           uuid.New(),
206			ChainDate:    date,
207			EntryCount:   len(entries),
208			BatchHash:    finalHash,
209			PreviousHash: previousHash,
210			CreatedAt:    time.Now(),
211		}
212	
213		if err := s.repo.CreateHashChain(ctx, chain); err != nil {
214			return nil, err
215		}
216	
217		return chain, nil
218	}
219	
220	// VerifyHashChain verifies the integrity of the hash chain for a given date
221	func (s *AuditService) VerifyHashChain(ctx context.Context, date time.Time) (bool, string, error) {
222		chain, err := s.repo.GetHashChainByDate(ctx, date)
223		if err != nil {
224			return false, "no hash chain found for this date", nil
225		}
226	
227		// Re-compute batch hash from entries
228		entries, err := s.repo.GetDayEntries(ctx, date)
229		if err != nil {
230			return false, "", fmt.Errorf("getting day entries: %w", err)
231		}
232	
233		batchHash := s.computeBatchHash(entries)
234	
235		// Re-compute chained hash
236		chainedInput := ""
237		if chain.PreviousHash != nil {
238			chainedInput = *chain.PreviousHash + "|"
239		}
240		chainedInput += batchHash
241		ch := sha256.Sum256([]byte(chainedInput))
242		expectedHash := hex.EncodeToString(ch[:])
243	
244		if chain.BatchHash != expectedHash {
245			return false, fmt.Sprintf("hash mismatch: expected %s, got %s", expectedHash, chain.BatchHash), nil
246		}
247	
248		if chain.EntryCount != len(entries) {
249			return false, fmt.Sprintf("entry count mismatch: expected %d, got %d", chain.EntryCount, len(entries)), nil
250		}
251	
252		return true, "integrity verified", nil
253	}
