294		csvDir := filepath.Join(storagePath, "audit-exports")
295		os.MkdirAll(csvDir, 0750)
296		csvPath := filepath.Join(csvDir, fmt.Sprintf("audit_%s.csv", uuid.New().String()))
297	
298		f, err := os.Create(csvPath)
299		if err != nil {
300			return "", fmt.Errorf("creating CSV: %w", err)
301		}
302		defer f.Close()
303	
304		w := csv.NewWriter(f)
305		defer w.Flush()
306	
307		w.Write([]string{
308			"id", "entity_type", "entity_id", "action", "actor_id", "tier",
309			"reason", "source", "workstation", "details",
310			"before_snapshot", "after_snapshot", "content_hash", "created_at",
311		})
312	
313		for _, l := range logs {
314			reason := ""
315			if l.Reason != nil {
316				reason = *l.Reason
317			}
318			source := ""
319			if l.Source != nil {
320				source = *l.Source
321			}
322			ws := ""
323			if l.Workstation != nil {
324				ws = *l.Workstation
325			}
326			hash := ""
327			if l.ContentHash != nil {
328				hash = *l.ContentHash
329			}
330	
331			w.Write([]string{
332				l.ID.String(),
333				l.EntityType,
334				l.EntityID.String(),
335				l.Action,
336				l.ActorID.String(),
337				string(l.Tier),
338				reason,
339				source,
340				ws,
341				string(l.Details),
342				string(l.BeforeSnapshot),
343				string(l.AfterSnapshot),
344				hash,
345				l.CreatedAt.Format(time.RFC3339),
346			})
347		}
348	
349		return csvPath, nil
350	}
