352	// VerifyEntryIntegrity checks a single entry's content hash
353	func (s *AuditService) VerifyEntryIntegrity(entry *models.AuditLog) bool {
354		if entry.ContentHash == nil {
355			return true // Pre-extension entries without hash are assumed valid
356		}
357		hashInput := fmt.Sprintf("%s|%s|%s|%s|%s|%s",
358			entry.EntityType, entry.EntityID, entry.ActorID,
359			entry.Action, string(entry.Details), entry.CreatedAt.Format(time.RFC3339Nano))
360		h := sha256.Sum256([]byte(hashInput))
361		return hex.EncodeToString(h[:]) == *entry.ContentHash
362	}
