155	func (h *ResourceHandler) UploadVersion(c echo.Context) error {
156		resourceID, err := uuid.Parse(c.Param("id"))
157		if err != nil {
158			return echo.NewHTTPError(http.StatusBadRequest, "invalid resource id")
159		}
160	
161		file, err := c.FormFile("file")
162		if err != nil {
163			return echo.NewHTTPError(http.StatusBadRequest, "file is required")
164		}
165	
166		src, err := file.Open()
167		if err != nil {
168			return echo.NewHTTPError(http.StatusInternalServerError, "failed to read uploaded file")
169		}
170		defer src.Close()
171	
172		mimeType := file.Header.Get("Content-Type")
173		if mimeType == "" {
174			mimeType = "application/octet-stream"
175		}
176	
177		// Extract text from request if provided (for PDF/DOCX)
178		extractedText := c.FormValue("extracted_text")
179		var extractedTextPtr *string
180		if extractedText != "" {
181			extractedTextPtr = &extractedText
182		}
183	
184		actorID, _ := c.Get("account_id").(uuid.UUID)
185		callerRole2, _ := c.Get("role").(models.Role)
186		version, err := h.resourceService.UploadVersion(c.Request().Context(), resourceID, file.Filename, mimeType, file.Size, src, extractedTextPtr, actorID, callerRole2)
187		if err != nil {
188			if errors.Is(err, service.ErrResourceNotFound) {
189				return echo.NewHTTPError(http.StatusNotFound, err.Error())
190			}
191			if errors.Is(err, service.ErrMimeTypeNotAllowed) {
192				return echo.NewHTTPError(http.StatusBadRequest, err.Error())
193			}
194			if errors.Is(err, service.ErrExtractedTextNotAllowed) {
195				return echo.NewHTTPError(http.StatusBadRequest, err.Error())
196			}
197			if errors.Is(err, service.ErrResourceAccessDenied) {
198				return echo.NewHTTPError(http.StatusForbidden, err.Error())
199			}
200			return echo.NewHTTPError(http.StatusInternalServerError, err.Error())
201		}
202	
203		return c.JSON(http.StatusCreated, dto.ToVersionResponse(version))
204	}
