226	func (h *ResourceHandler) DownloadVersion(c echo.Context) error {
227		versionID, err := uuid.Parse(c.Param("version_id"))
228		if err != nil {
229			return echo.NewHTTPError(http.StatusBadRequest, "invalid version id")
230		}
231	
232		callerID, _ := c.Get("account_id").(uuid.UUID)
233		callerRole, _ := c.Get("role").(models.Role)
234	
235		version, err := h.resourceService.GetDownloadPath(c.Request().Context(), versionID, callerID, callerRole)
236		if err != nil {
237			if errors.Is(err, service.ErrVersionNotFound) || errors.Is(err, service.ErrResourceNotFound) {
238				return echo.NewHTTPError(http.StatusNotFound, err.Error())
239			}
240			if errors.Is(err, service.ErrResourceAccessDenied) {
241				return echo.NewHTTPError(http.StatusForbidden, err.Error())
242			}
243			return echo.NewHTTPError(http.StatusInternalServerError, "internal server error")
244		}
245	
246		// Verify file integrity before serving
247		f, err := os.Open(version.StoragePath)
248		if err != nil {
249			return echo.NewHTTPError(http.StatusInternalServerError, "file not found on disk")
250		}
251		defer f.Close()
252	
253		hasher := sha256.New()
254		if _, err := io.Copy(hasher, f); err != nil {
255			return echo.NewHTTPError(http.StatusInternalServerError, "failed to verify file integrity")
256		}
257		actualHash := hex.EncodeToString(hasher.Sum(nil))
258		if actualHash != version.SHA256Hash {
259			return echo.NewHTTPError(http.StatusInternalServerError, "file integrity check failed")
260		}
261	
262		// Seek back to start for serving
263		f.Seek(0, io.SeekStart)
264	
265		c.Response().Header().Set("Content-Type", version.MimeType)
266		c.Response().Header().Set("Content-Disposition", fmt.Sprintf(`attachment; filename="%s"`, version.FileName))
267		c.Response().Header().Set("X-Content-SHA256", version.SHA256Hash)
268		return c.Stream(http.StatusOK, version.MimeType, f)
269	}
